import { callMcpSkill } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const targetQuery = "Will Paris Saint-Germain FC win on 2026-04-08?";

  const discovery = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query: targetQuery,
      category: "sports"
    }
  });

  const outcomes = Array.isArray(discovery?.outcomes) ? discovery.outcomes : [];
  const ranked = pickTopSemanticCandidates({
    target: targetQuery,
    candidates: outcomes,
    requiredTerms: ["Paris Saint-Germain FC", "2026-04-08"],
    avoidTerms: ["will", "win", "market"],
    limit: 3
  });

  const selected = Array.isArray(ranked) ? ranked[0] : null;
  const tokenId = selected && typeof selected.tokenId === "string" ? selected.tokenId : null;

  if (!tokenId) {
    return {
      error: "No matching token found after discovery and semantic ranking",
      targetQuery,
      eventTitle: discovery?.eventTitle || null,
      fetchedAt: discovery?.fetchedAt || null,
      attemptedBranches: ["search_and_get_outcomes", "pickTopSemanticCandidates"],
      missingData: ["tokenId"]
    };
  }

  const params = await callMcpSkill({
    toolId,
    toolName: "get_market_parameters",
    args: { tokenId }
  });

  return {
    targetQuery,
    eventTitle: discovery?.eventTitle || null,
    matchedOutcome: selected?.matchedName || selected?.name || null,
    tokenId: params.tokenId,
    tradingParameters: {
      tickSize: params.tickSize,
      feeRateBps: params.feeRateBps,
      minOrderSize: params.minOrderSize,
      negRisk: params.negRisk
    },
    fetchedAt: params.fetchedAt,
    discoveryFetchedAt: discovery?.fetchedAt || null
  };
}

